        new() { Id = 2, TrackingNumber = "TRK-100202", Origin = "Shanghai, CN", Destination = "Los Angeles, US", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "bob@example.com", Description = "Auto parts - 1 pallet" },
        new() { Id = 3, TrackingNumber = "TRK-100203", Origin = "Berlin, DE", Destination = "Tokyo, JP", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(5), CustomerEmail = "carol@example.com", Description = "Medical supplies - 5 boxes" },
        new() { Id = 4, TrackingNumber = "TRK-100204", Origin = "São Paulo, BR", Destination = "Miami, US", Status = ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-10), EstimatedDelivery = DateTime.UtcNow.AddDays(-2), CustomerEmail = "dave@example.com", Description = "Textiles - 3 cartons" },
        new() { Id = 5, TrackingNumber = "TRK-100205", Origin = "Mumbai, IN", Destination = "Sydney, AU", Status = ShipmentStatus.Delayed, ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "eve@example.com", Description = "Machinery - 1 crate" },
        new() { Id = 6, TrackingNumber = "TRK-100206", Origin = "Paris, FR", Destination = "Toronto, CA", Status = ShipmentStatus.PickedUp, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(4), CustomerEmail = "frank@example.com", Description = "Food products - 8 boxes" },
    ];

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }
}

