@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th @onclick="() => SortBy(nameof(Shipment.TrackingNumber))" style="cursor:pointer">
                    Tracking # @SortIndicator(nameof(Shipment.TrackingNumber))
                </th>
                <th @onclick="() => SortBy(nameof(Shipment.Destination))" style="cursor:pointer">
                    Destination @SortIndicator(nameof(Shipment.Destination))
                </th>
                <th @onclick="() => SortBy(nameof(Shipment.Status))" style="cursor:pointer">
                    Status @SortIndicator(nameof(Shipment.Status))
                </th>
                <th>Est. Delivery</th>
                <th>Description</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>@s.Description</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                                @onchange="e => UpdateStatus(s, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string sortColumn = nameof(Shipment.TrackingNumber);
    private bool sortAscending = true;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrWhiteSpace(filterText)
                || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
                || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .OrderBy(s => sortColumn switch
            {
                nameof(Shipment.Destination) => s.Destination as object,
                nameof(Shipment.Status) => s.Status as object,
                _ => s.TrackingNumber as object
            }, sortAscending ? Comparer<object>.Default : Comparer<object>.Create((a, b) => Comparer<object>.Default.Compare(b, a)));

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column) =>
        sortColumn == column ? (sortAscending ? "▲" : "▼") : "";

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-light text-dark"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-100201)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>".
        Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>

                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                    </dl>
                </div>
            </div>

            @{
                var progress = GetDeliveryProgress(shipment);
            }
            <div class="mt-3">
                <label class="form-label">Delivery Progress</label>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar" style="width: @(progress)%">
                        @(progress)%
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool isSearching;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        searched = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static int GetDeliveryProgress(Shipment s) => s.Status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 40,
        _ => 0
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-light text-dark"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => ""
    };
}
